import React, {useRef} from 'react'
import styled from 'styled-components'
import avatar from './static/HedMayner.png'
import {useDispatch} from 'react-redux'
import {setProfileUpdateActive} from '../redux/accountSlice'
import {setSidebarCategoryActive} from '../redux/messageSlice'


const Header = styled.div `
display:flex;
justify-content:space-between;
align-items:center;
margin:20px 0;
`

const PhotoWrapper = styled.label `
border-radius:50%;
width:150px;
height:150px;
background-color:rgba(60, 60, 60, 0.4);
display:none;
font-size:0.8rem;
font-weight:700;
color:white;
text-align:center;
line-height:150px
`

const Avatar = styled.div `
border-radius:50%;
width:150px;
height:150px;
background-image:url(${avatar});
background-position:center;
background-size:cover;
&:hover ${PhotoWrapper} {
	display:block;
	cursor:pointer;
}
`


const LeftPart = styled.div `
display:flex;
justify-content:center;
align-items:center;
`

const Username = styled.div `
margin:0 40px;
`

const SeparationLineStraight = styled.div `
background-color:grey;
height:60px;
width:1px;
`

const TransactionWrapper = styled.div `
margin:0 40px;
display:flex;
justify-content:center;
align-items:center;
flex-direction:column;
`

const Transaction = styled.div `
font-size:1.2rem;
font-weight:800;
`

const TransactionWord = styled.div `
font-size:0.8rem;
`

const FollowersWrappper = styled.div `
margin:0 40px;
display:flex;
justify-content:center;
align-items:center;
flex-direction:column;
`

const Followers = styled.div `
font-size:1.2rem;
font-weight:800;
`

const FollowersWord = styled.div `
font-size:0.8rem;
`

const EditProfile = styled.div `
text-align:center;
line-height:40px;
width:150px;
height:40px;
background-color:#1C1C1C;
border-radius:7px;
border:1.5px solid #1C1C1C;
color:white;
font-size:0.9rem;
&:hover {
	cursor:pointer;
	background-color:white;
	color:#1C1C1C;
	border:1.5px solid #1C1C1C;
}
`

const SeparationLineBig = styled.hr `
background-color:grey;
`



const PhotoInput = styled.input `
display:none;
`

export default function MeHeader () {
	const dispatch = useDispatch()
	const photoRef = useRef(null)
	const photoWrapperRef = useRef(null)

	const onEditProfile = () => {
		dispatch(setSidebarCategoryActive(['myProfileActive', 'myItemsActive', 'messageActive', 'settingsActive']))
		dispatch(setProfileUpdateActive())
	}

	const onImageUpload = () => {
		const reader = new FileReader()
		reader.readAsDataURL(photoRef.current.files[0])
		reader.addEventListener('load', () => {
			const uploaded_result = reader.result
			photoWrapperRef.current.style.backgroundImage = `url(${uploaded_result})`
			photoWrapperRef.current.style.backgroundSize = 'cover'
			photoWrapperRef.current.style.backgroundPosition = 'center'
		})

	}


	return (
		<>
		<Header>
			<LeftPart>
				<Avatar ref={photoWrapperRef} >
						<PhotoWrapper>UPLOAD PHOTO
							<PhotoInput ref={photoRef} onChange={onImageUpload} type='file' accept='image/png, image/jpg'></PhotoInput>
						</PhotoWrapper>
				</Avatar>
				<Username>{localStorage.getItem('username')}</Username>
				<SeparationLineStraight />
				<TransactionWrapper>
					<Transaction>3</Transaction>
					<TransactionWord>Transactions</TransactionWord>
				</TransactionWrapper>
				<SeparationLineStraight />
				<FollowersWrappper>
					<Followers>3</Followers>
					<FollowersWord>Transactions</FollowersWord>
				</FollowersWrappper>
			</LeftPart>
			<EditProfile onClick={onEditProfile}>Edit Profile</EditProfile>
		</Header>
		<SeparationLineBig/>
		</>
	)
}
